                    </div>
                    <div className="text-[10px] tracking-[0.1em] uppercase text-mid">Current Price</div>
                </div>
            </div>

            <div className="flex-1 min-h-0 flex gap-12">
                {/* Left Side - Stats */}
                <div className="w-1/3 flex flex-col gap-8">
